#include <bits/stdc++.h>
using namespace std;
int main()
{
    string s;
    getline(cin,s);
    for (int i=0;i<=s.size()-1;i++)
    {
        if (s[i]>='A'&&s[i]<='W'||s[i]>='a'&&s[i]<='w')
        {
            s[i]+=3;
        }
        else
        {
            s[i]-=23;
        }
        if (s[i]>='A'&&s[i]<='Z')
        {
            s[i]+=32;
        }
        else
        {
            s[i]-=32;
        }
    }
    reverse(s.begin(),s.end());
    cout<<s;
}
